#!/usr/bin/env python3
import base64, struct

with open("bruce_rsa_6e7ecd53b443a97013397b1a1ea30e14.pub") as f:
    pub = f.read()

# ssh-rsa format: [type_len][type][e_len][e][n_len][n]
data = base64.b64decode(pub.split()[1])

def read_field(data, offset):
    length = struct.unpack('>I', data[offset:offset+4])[0]
    return data[offset+4:offset+4+length], offset+4+length

key_type, offset = read_field(data, 0)
e_bytes, offset = read_field(data, offset)
n_bytes, offset = read_field(data, offset)

n = int.from_bytes(n_bytes, 'big')
print(n)
